import{_ as t,o,c as a,a2 as s}from"./chunks/framework.B08aFN1B.js";const g=JSON.parse('{"title":"Command Palette & Help","description":"","frontmatter":{},"headers":[],"relativePath":"palette-and-help.md","filePath":"palette-and-help.md","lastUpdated":null}'),n={name:"palette-and-help.md"};function r(l,e,i,d,p,c){return o(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="Command-Palette-and-Help" tabindex="-1">Command Palette &amp; Help <a class="header-anchor" href="#Command-Palette-and-Help" aria-label="Permalink to &quot;Command Palette &amp; Help {#Command-Palette-and-Help}&quot;">​</a></h1><p>Two keyboard-driven tools make everything in the notebook reachable without hunting through menus: the <strong>command palette</strong> (⌘K) for actions, and the <strong>help dock</strong> (⌘⇧K) for documentation.</p><h2 id="Command-palette-—-K" tabindex="-1">Command palette — ⌘K <a class="header-anchor" href="#Command-palette-—-K" aria-label="Permalink to &quot;Command palette — ⌘K {#Command-palette-—-K}&quot;">​</a></h2><p>Press <strong>⌘K</strong> (or click the <strong>⌘K</strong> hint in the top bar) to open a fuzzy-searchable list of <em>every</em> action, each with its keyboard shortcut. Type to filter, <strong>↑/↓</strong> to move, <strong>↵</strong> to run.</p><p><img class="slate-shot" src="https://github.com/kahliburke/KaimonSlate.jl/releases/download/docs-assets/command-palette.png" alt=""></p><p>It&#39;s not just commands — entries are tagged so the palette doubles as an insert menu and a navigator:</p><ul><li><p><strong>Cell actions</strong> — add / move / delete / convert / split / merge, run stale, show a cell&#39;s dependency chain.</p></li><li><p><strong>Panels</strong> — Packages, Worker log, <a href="./history">Timeline</a>.</p></li><li><p><strong>Export</strong> — HTML, publication PDF, print, or self-contained <code>.jl</code> (see <a href="./export">Export</a>).</p></li><li><p><strong><code>@bind</code> snippets</strong> — insert any widget (<code>Slider</code>, <code>Toggle</code>, <code>Select</code>, …) as a ready-to-edit snippet.</p></li><li><p><strong>Recipes</strong> — drop in a starter chart or table cell.</p></li><li><p><strong>Jump to cell</strong> — every cell id is listed; pick one to scroll to and select it.</p></li><li><p><strong>VS Code / project</strong> — open the notebook or its project in your editor; open Settings; jump back to the notebook index.</p></li></ul><p>Single-letter and ⇧-shortcuts are <em>command-mode</em> (a cell is selected and you&#39;re not editing it); ⌘-shortcuts work globally, including from inside the editor.</p><h2 id="Help-and-docs-search-—-K" tabindex="-1">Help &amp; docs search — ⌘⇧K <a class="header-anchor" href="#Help-and-docs-search-—-K" aria-label="Permalink to &quot;Help &amp; docs search — ⌘⇧K {#Help-and-docs-search-—-K}&quot;">​</a></h2><p>Press <strong>⌘⇧K</strong> to open the <strong>help dock</strong>. With the cursor on a symbol it opens that symbol&#39;s documentation directly; otherwise it&#39;s a search box over the notebook&#39;s package docs (a hybrid semantic + full-text query — press <strong>↵</strong> to run it).</p><p><img class="slate-shot" src="https://github.com/kahliburke/KaimonSlate.jl/releases/download/docs-assets/help-docs.png" alt=""></p><p>The dock is built for <em>drilling in</em>, not just one lookup:</p><ul><li><p><strong>Clickable references</strong> — type names in a signature (<code>Vector</code>, <code>Float64</code>, …) and inline $<code>code</code>$ names in the docstring become links; click to open that symbol&#39;s help.</p></li><li><p><strong>Exports grid</strong> — looking up a module lists its exports as chips, colour-coded by kind; click to dive into any of them.</p></li><li><p><strong>Related rail</strong> — neighbouring/related items are offered alongside the doc.</p></li><li><p><strong>Back / forward</strong> — <strong>‹ ›</strong> walk your lookup history; <strong>esc</strong> dismisses the dock.</p></li><li><p><strong>Insert</strong> — <strong>↵</strong> drops the bare name at the selected cell&#39;s cursor (or copies the qualified name if no cell is focused).</p></li></ul><p>Because it reads the <em>notebook&#39;s</em> environment, the help reflects exactly the package versions loaded in this notebook — including packages you added through the <a href="./packages">Packages</a> panel.</p>',14)])])}const m=t(n,[["render",r]]);export{g as __pageData,m as default};
